const serpData = $input.first().json;
const items = serpData.items || serpData.organic_results || [];

const urls = items
  .filter(item => item.link || item.url)
  .map(item => ({
    url: item.link || item.url,
    title: item.title || '',
    snippet: item.snippet || item.description || ''
  }));

return [{ json: { urls, total: urls.length, keyword: $('Preparar Data').first().json.target_keyword } }];

const scraped = $input.first().json.data || [];
const contexts = scraped.map((item, i) => ({
  index: i + 1,
  url: item.url || '',
  content: typeof item === 'string' ? item.substring(0, 3000) : JSON.stringify(item).substring(0, 3000)
}));

return [{ json: { scraped_contexts: contexts, count: contexts.length } }];

