parameters.jsCode:
const blueprint = $input.first().json;
const output = blueprint.output || blueprint.text || JSON.stringify(blueprint);

// Validaciones básicas
const hasH1 = output.toLowerCase().includes('h1') || output.toLowerCase().includes('título');
const hasH2 = output.toLowerCase().includes('h2') || output.toLowerCase().includes('sección');
const wordCount = output.split(' ').length;

const validation = {
  is_valid: hasH1 && hasH2 && wordCount > 50,
  has_h1: hasH1,
  has_h2: hasH2,
  blueprint_word_count: wordCount,
  warnings: []
};

if (!hasH1) validation.warnings.push('Missing H1 structure');
if (!hasH2) validation.warnings.push('Missing H2 structure');

return [{ json: { blueprint: output, validation, raw: blueprint } }];

const FORBIDDEN_COMPETITORS = [
  'bet365', 'betano', 'sportingbet', 'pixbet', 'estrelabet',
  'betnacional', '1xbet', 'stake.com', 'kto.com', 'galera.bet',
  'blaze', 'rivalo', 'parimatch', 'betfair', 'superbet', 'novibet'
];

const item = $input.first().json;
const blueprint = item.blueprint || '';
const brand_contract = (item.raw && item.raw.brand_contract) || {};

const forbiddenList = brand_contract.forbidden_competitors || FORBIDDEN_COMPETITORS;

let sanitized = blueprint;
const found_competitors = [];

forbiddenList.forEach(comp => {
  const regex = new RegExp(comp.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
  if (regex.test(sanitized)) {
    found_competitors.push(comp);
    sanitized = sanitized.replace(regex, '[COMPETIDOR]');
  }
});

const sanitization_report = {
  competitors_found: found_competitors,
  total_replaced: found_competitors.length,
  sanitized_at: new Date().toISOString()
};

return [{ json: { ...item, blueprint: sanitized, sanitization_report } }];

const item = $input.first().json;
const db_record = item.db_record || $('Preparar Data').first().json.db_record || {};
const brand_slug = db_record.brand_slug || item.brand_slug || '';

// BUG FIX: fallback cambiado de 'vera-bet' a 'sin-brand'
const resolvedSlug = brand_slug || 'sin-brand';

const brand_contract = {
  brand_slug: resolvedSlug,
  brand_name: resolvedSlug,
  language: db_record.language || 'es',
  market: db_record.market || 'es-MX',
  branded_products: [],
  forbidden_competitors: [
    'bet365', 'betano', 'sportingbet', 'pixbet', 'estrelabet',
    'betnacional', '1xbet', 'stake.com', 'kto.com', 'galera.bet'
  ],
  writing_rules: [
    'Nunca mencionar competidores',
    'Mínimo 2 menciones a la marca por artículo'
  ],
  contract_version: 'injected-v1'
};

const brief_final = {
  ...(item.brief_final || {}),
  brand_contract,
  blueprint: item.blueprint || '',
  sanitization_report: item.sanitization_report || {},
  target_keyword: db_record.main_keyword || item.target_keyword || '',
  language: db_record.language || 'es'
};

return [{ json: { ...item, brief_final, db_record } }];

const LANG_TO_COUNTRY = { 'en': 'us', 'pt': 'br', 'es': 'mx' };

const item = $input.first().json;
const dbRec = item.db_record || {};
const keyword = dbRec.main_keyword || '';
const lang = (dbRec.language || '').toLowerCase();
const country = LANG_TO_COUNTRY[lang] || 'us';

if (!keyword) {
  return [{ json: { ...item, _ahrefs_skip: true, _ahrefs_ctx: null } }];
}

return [{ json: { ...item, _ahrefs_ctx: { keyword, country, lang } } }];

function safeArr(x) { return Array.isArray(x) ? x : []; }

const COMPETITORS = ['bet365.com','betano.com.br','sportingbet.com','pixbet.com','estrelabet.com','betnacional.com','1xbet.com','stake.com','kto.com','galera.bet'];
function isCompetitor(url) {
  if (!url) return false;
  return COMPETITORS.some(d => url.toLowerCase().includes(d));
}

const items = $input.all();
const data = items.reduce((acc, it) => ({ ...acc, ...it.json }), {});

const overview = data.overview || data.keyword_overview || (data.keywords && data.keywords[0]) || {};
const serpRaw = data.serp_overview || data.positions || [];
const questions = safeArr(data.questions || data.matching_terms);
const related = safeArr(data.related_terms);
const alsoRank = safeArr(data.also_rank_for);

const serpFiltered = safeArr(serpRaw).filter(r => !isCompetitor(r.url || r.target_url));
const totalSerp = serpFiltered.length || 1;
const avgWords = Math.round(serpFiltered.reduce((s, r) => s + (r.word_count || 0), 0) / totalSerp);
const avgH2 = Math.round(serpFiltered.reduce((s, r) => s + (r.h2_count || 0), 0) / totalSerp);
const withFaq = serpFiltered.filter(r => r.has_schema_faq || r.has_faq).length;
const hasFs = serpFiltered.some(r => r.has_featured_snippet);

const faqTop = questions.sort((a, b) => (b.volume||0)-(a.volume||0)).slice(0,8).map(q => ({ question: q.keyword, volume: q.volume||0 }));
const lsiTop = related.filter(k => (k.keyword_difficulty||99)<30 && (k.volume||0)>100).sort((a,b)=>(b.volume||0)-(a.volume||0)).slice(0,15).map(k=>({keyword:k.keyword,volume:k.volume||0,kd:k.keyword_difficulty||null}));
const alsoTop = alsoRank.sort((a,b)=>(b.volume||0)-(a.volume||0)).slice(0,10).map(k=>({keyword:k.keyword,volume:k.volume||0}));

const ahrefs_research = {
  keyword_metrics: {
    volume: overview.volume||null,
    keyword_difficulty: overview.keyword_difficulty||null,
    traffic_potential: overview.traffic_potential||null,
    cpc: overview.cpc||null,
    global_volume: overview.global_volume||null,
    parent_topic: overview.parent_topic||null,
    search_intent: overview.search_intent||null
  },
  serp_benchmarks: {
    avg_word_count: avgWords||null,
    avg_h2_count: avgH2||null,
    pct_with_faq: totalSerp ? +(withFaq/totalSerp).toFixed(2) : null,
    has_featured_snippet: hasFs,
    serp_top3_titles: serpFiltered.slice(0,3).map(r=>r.title).filter(Boolean),
    competitors_filtered_out: safeArr(serpRaw).length - serpFiltered.length
  },
  recommended_structure: {
    target_word_count: avgWords||1500,
    suggested_h2_count: avgH2||5,
    faq_required: totalSerp ? (withFaq/totalSerp)>=0.6 : true,
    featured_snippet_target: hasFs
  },
  faq_questions: faqTop,
  lsi_keywords: lsiTop,
  also_rank_for: alsoTop,
  data_fetched_at: new Date().toISOString(),
  ahrefs_credits_used: 5,
  ahrefs_partial_failure: !overview.volume && serpFiltered.length === 0
};

// Recover original payload (from Preparar contexto node) and add ahrefs_research to brief_final
const originalPayload = $('Ahrefs: Preparar contexto').first().json;
const { _ahrefs_ctx, _ahrefs_skip, ...rest } = originalPayload;

return [{ json: { ...rest, brief_final: { ...rest.brief_final, ahrefs_research } } }];
